import json
import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
import os
from datetime import datetime

# Initialize clients
storage_client = storage.Client()
db = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Configuration
PROJECT_ID = os.environ.get('GCP_PROJECT', 'your-project-id')
PUBSUB_TOPIC = f'projects/{PROJECT_ID}/topics/file-processing-topic'
FIRESTORE_COLLECTION = 'processed_files'

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    """
    Triggered by Cloud Storage when a file is uploaded.
    Processes the file, writes metadata to Firestore, and publishes to Pub/Sub.
    """
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    content_type = data.get('contentType', 'unknown')
    size = data.get('size', 0)
    time_created = data.get('timeCreated', '')
    
    print(f'Processing file: {file_name} from bucket: {bucket_name}')
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        # Download file content
        file_content = blob.download_as_bytes()
        
        # Process file content (example: count bytes and lines if text)
        file_info = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'content_type': content_type,
            'size_bytes': int(size),
            'time_created': time_created,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'processed'
        }
        
        # Try to decode if text file
        if content_type and 'text' in content_type:
            try:
                text_content = file_content.decode('utf-8')
                file_info['line_count'] = len(text_content.split('\n'))
                file_info['char_count'] = len(text_content)
            except Exception as e:
                print(f'Could not decode text: {e}')
        
        # Write to Firestore
        doc_ref = db.collection(FIRESTORE_COLLECTION).document()
        doc_ref.set(file_info)
        file_info['firestore_doc_id'] = doc_ref.id
        
        print(f'Written to Firestore: {doc_ref.id}')
        
        # Publish to Pub/Sub
        message_data = json.dumps(file_info).encode('utf-8')
        future = publisher.publish(PUBSUB_TOPIC, message_data)
        message_id = future.result()
        
        print(f'Published to Pub/Sub: {message_id}')
        
        return {
            'status': 'success',
            'file': file_name,
            'firestore_doc': doc_ref.id,
            'pubsub_message': message_id
        }
        
    except Exception as e:
        error_info = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'error': str(e),
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'error'
        }
        
        # Log error to Firestore
        db.collection(FIRESTORE_COLLECTION).document().set(error_info)
        
        print(f'Error processing file: {e}')
        raise


@functions_framework.http
def process_http_request(request):
    """
    HTTP endpoint to manually trigger file processing.
    Expects JSON with bucket_name and file_name.
    """
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket_name' not in request_json or 'file_name' not in request_json:
        return {'error': 'Missing bucket_name or file_name'}, 400
    
    bucket_name = request_json['bucket_name']
    file_name = request_json['file_name']
    
    try:
        # Read file from Cloud Storage
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': 'File not found'}, 404
        
        file_content = blob.download_as_bytes()
        metadata = blob.metadata or {}
        
        file_info = {
            'file_name': file_name,
            'bucket_name': bucket_name,
            'content_type': blob.content_type,
            'size_bytes': blob.size,
            'time_created': blob.time_created.isoformat() if blob.time_created else None,
            'processed_at': datetime.utcnow().isoformat(),
            'status': 'processed',
            'metadata': metadata
        }
        
        # Write to Firestore
        doc_ref = db.collection(FIRESTORE_COLLECTION).document()
        doc_ref.set(file_info)
        file_info['firestore_doc_id'] = doc_ref.id
        
        # Publish to Pub/Sub
        message_data = json.dumps(file_info).encode('utf-8')
        future = publisher.publish(PUBSUB_TOPIC, message_data)
        message_id = future.result()
        
        return {
            'status': 'success',
            'file': file_name,
            'firestore_doc': doc_ref.id,
            'pubsub_message': message_id,
            'size': blob.size
        }, 200
        
    except Exception as e:
        return {'error': str(e)}, 500


@functions_framework.cloud_event
def process_pubsub_message(cloud_event):
    """
    Triggered by Pub/Sub messages.
    Processes messages and updates Firestore.
    """
    pubsub_message = base64.b64decode(cloud_event.data['message']['data']).decode('utf-8')
    
    try:
        message_data = json.loads(pubsub_message)
        
        print(f'Processing Pub/Sub message: {message_data}')
        
        # Update or create Firestore document
        update_info = {
            'pubsub_processed_at': datetime.utcnow().isoformat(),
            'message_data': message_data,
            'status': 'pubsub_processed'
        }
        
        doc_ref = db.collection(f'{FIRESTORE_COLLECTION}_pubsub').document()
        doc_ref.set(update_info)
        
        print(f'Pub/Sub message processed and saved to Firestore')
        
    except Exception as e:
        print(f'Error processing Pub/Sub message: {e}')
        raise


def list_files_in_bucket(bucket_name, prefix=''):
    """
    Utility function to list files in a bucket.
    """
    bucket = storage_client.bucket(bucket_name)
    blobs = bucket.list_blobs(prefix=prefix)
    
    files = []
    for blob in blobs:
        files.append({
            'name': blob.name,
            'size': blob.size,
            'content_type': blob.content_type,
            'created': blob.time_created.isoformat() if blob.time_created else None
        })
    
    return files


def query_firestore_documents(limit=100):
    """
    Utility function to query Firestore documents.
    """
    docs = db.collection(FIRESTORE_COLLECTION).limit(limit).stream()
    
    results = []
    for doc in docs:
        doc_dict = doc.to_dict()
        doc_dict['id'] = doc.id
        results.append(doc_dict)
    
    return results